  // Generate more questions to reach 200
  const moreQuestions = [
    { stem: "Which form of insulin has the longest duration of action?", options: ["Lispro (Humalog)", "Regular (Humulin R)", "NPH (Humulin N)", "Glargine (Lantus)"], correctIndex: 3, rationale: "Insulin glargine (Lantus) is a long-acting insulin with a duration of up to 24 hours. Lispro is rapid-acting (3-5 hr), Regular is short-acting (6-8 hr), NPH is intermediate-acting (12-18 hr).", category: "Pharmacology", difficulty: 2 },
    { stem: "What does NDC stand for?", options: ["National Drug Code", "New Drug Classification", "National Dispensing Code", "Narcotic Drug Category"], correctIndex: 0, rationale: "NDC stands for National Drug Code — a unique 10-digit identifier for each medication. It identifies the labeler/manufacturer, product/strength/dosage form, and package size.", category: "Prescription Processing", difficulty: 1 },
    { stem: "Which of the following is a Schedule V controlled substance?", options: ["Oxycodone", "Alprazolam", "Pregabalin (Lyrica)", "Testosterone"], correctIndex: 2, rationale: "Pregabalin (Lyrica) is a Schedule V controlled substance with the lowest abuse potential of all scheduled drugs. Oxycodone is C-II, alprazolam is C-IV, testosterone is C-III.", category: "Regulations/Law", difficulty: 2 },
    { stem: "How many grams of drug are in 500 mL of a 5% w/v solution?", options: ["5 g", "10 g", "25 g", "50 g"], correctIndex: 2, rationale: "5% w/v = 5 g per 100 mL. For 500 mL: (5 g / 100 mL) × 500 mL = 25 g. Percent w/v always means grams per 100 mL of solution.", category: "Dosage Calculations", difficulty: 2 },
    { stem: "What is the primary concern with combining MAOIs and tyramine-rich foods?", options: ["Hypoglycemia", "Hypertensive crisis", "Hepatotoxicity", "Nephrotoxicity"], correctIndex: 1, rationale: "MAOIs (monoamine oxidase inhibitors) prevent the breakdown of tyramine. Tyramine accumulation causes massive norepinephrine release, leading to severe hypertension (hypertensive crisis). Foods to avoid include aged cheese, red wine, and cured meats.", category: "Drug Interactions", difficulty: 3 },
    { stem: "What mortar type should be used for grinding hard, crystalline substances?", options: ["Glass mortar", "Wedgwood mortar", "Porcelain mortar", "Stainless steel mortar"], correctIndex: 1, rationale: "Wedgwood mortars have a rough, unglazed interior surface that provides good abrasion for grinding hard substances. Glass mortars are for liquids and staining materials. Porcelain is general purpose but less abrasive.", category: "Compounding", difficulty: 2 },
    { stem: "Which error-prone abbreviation should be avoided and written out instead?", options: ["mg", "mL", "U (for units)", "PO"], correctIndex: 2, rationale: "'U' for units is on the ISMP 'Do Not Use' list because it can be mistaken for 0, 4, or cc. Always write out 'units' to prevent potentially fatal insulin and heparin dosing errors.", category: "Patient Safety", difficulty: 1 },
    { stem: "An opened vial of insulin stored at room temperature is generally good for how many days?", options: ["7 days", "14 days", "28-30 days", "90 days"], correctIndex: 2, rationale: "Most opened insulin vials are stable at room temperature for 28-30 days (varies by type). After this period, they should be discarded even if medication remains. Unopened insulin should be refrigerated at 2-8°C.", category: "Inventory Management", difficulty: 2 },
    { stem: "What is the function of a laminar airflow workbench (LAFW)?", options: ["To store compounded preparations", "To provide a sterile ISO Class 5 environment for compounding", "To sterilize equipment using heat", "To test finished products for contamination"], correctIndex: 1, rationale: "A LAFW provides HEPA-filtered, unidirectional airflow creating an ISO Class 5 (Class 100) environment for sterile compounding. It removes particles ≥0.3 μm with 99.97% efficiency.", category: "Sterile Products", difficulty: 1 },
    { stem: "Which of the following is NOT a required element of a valid prescription?", options: ["Patient name", "Drug name and strength", "Patient's Social Security number", "Prescriber signature"], correctIndex: 2, rationale: "A patient's Social Security number is NOT required on a prescription. Required elements include patient name, date of birth, date written, drug name/strength/quantity, directions, refills, and prescriber information with signature.", category: "Prescription Processing", difficulty: 1 },
    { stem: "What is the brand name for amlodipine?", options: ["Lopressor", "Norvasc", "Zocor", "Cozaar"], correctIndex: 1, rationale: "Norvasc is the brand name for amlodipine, a dihydropyridine calcium channel blocker. Lopressor = metoprolol (beta-blocker), Zocor = simvastatin (statin), Cozaar = losartan (ARB).", category: "Pharmacology", difficulty: 1 },
    { stem: "Which DEA form is used for ordering Schedule II controlled substances?", options: ["DEA Form 41", "DEA Form 106", "DEA Form 222", "DEA Form 224"], correctIndex: 2, rationale: "DEA Form 222 (or CSOS electronic ordering) is required for ordering Schedule II controlled substances. Form 106 is for theft/loss reporting. Form 41 is for destruction. Form 224 is for new registration.", category: "Regulations/Law", difficulty: 2 },
    { stem: "A child weighs 44 lb. Using Clark's Rule, what fraction of the adult dose should the child receive?", options: ["About 1/4 of the adult dose", "About 1/3 of the adult dose", "About 1/2 of the adult dose", "About 2/3 of the adult dose"], correctIndex: 1, rationale: "Clark's Rule: Child dose = (Weight in lb / 150) × Adult dose. 44/150 = 0.293, which is approximately 1/3 (29.3%) of the adult dose.", category: "Dosage Calculations", difficulty: 3 },
    { stem: "Which recall class involves products that are unlikely to cause adverse health consequences?", options: ["Class I", "Class II", "Class III", "Class IV"], correctIndex: 2, rationale: "Class III recalls involve products that are not likely to cause adverse health consequences (e.g., minor labeling issues). Class I is most serious (death/serious harm), Class II is moderately serious (temporary/reversible effects). There is no Class IV.", category: "Inventory Management", difficulty: 1 },
    { stem: "How often must controlled substance records be retained at minimum?", options: ["1 year", "2 years", "5 years", "7 years"], correctIndex: 1, rationale: "Federal law requires all controlled substance records to be retained for a minimum of 2 years. Some states may require longer retention periods. C-II records must be kept separate from all other records.", category: "Regulations/Law", difficulty: 2 },
    { stem: "What is the therapeutic class of metoprolol?", options: ["ACE inhibitor", "Calcium channel blocker", "Beta-blocker", "ARB"], correctIndex: 2, rationale: "Metoprolol is a beta-1 selective blocker used for hypertension, angina, and heart failure. The -olol suffix identifies it as a beta-blocker. It comes in two salt forms: tartrate (Lopressor, BID) and succinate (Toprol-XL, daily).", category: "Pharmacology", difficulty: 1 },
    { stem: "Which compounding technique involves reducing particle size by grinding with a pestle?", options: ["Levigation", "Spatulation", "Trituration", "Geometric dilution"], correctIndex: 2, rationale: "Trituration is the process of reducing particle size by grinding in a mortar with a pestle. Levigation uses a liquid to reduce particle size. Spatulation mixes on an ointment slab. Geometric dilution ensures uniform drug distribution.", category: "Compounding", difficulty: 1 },
    { stem: "What is the primary reason for using Tall Man Lettering?", options: ["To make drug names easier to pronounce", "To distinguish between look-alike/sound-alike drug names", "To indicate controlled substance status", "To identify brand-name drugs"], correctIndex: 1, rationale: "Tall Man Lettering capitalizes distinguishing letters in drug name pairs that look or sound similar (LASA drugs) to prevent medication errors. Examples: DOBUTamine vs DOPamine, predniSONE vs prednisoLONE.", category: "Patient Safety", difficulty: 1 },
    { stem: "What solution is used to disinfect the interior of a LAFW before compounding?", options: ["Hydrogen peroxide 3%", "Bleach 10%", "Sterile water", "70% isopropyl alcohol"], correctIndex: 3, rationale: "70% isopropyl alcohol (IPA) is used to disinfect the interior surfaces of the LAFW before and during compounding. Wipe from back to front (cleanest to dirtiest) and from top to bottom. Allow to air dry.", category: "Sterile Products", difficulty: 1 },
    { stem: "A prescription reads 'Amoxicillin 500 mg PO TID × 10 days.' How many capsules should be dispensed?", options: ["10 capsules", "20 capsules", "30 capsules", "40 capsules"], correctIndex: 2, rationale: "TID = three times daily. 3 capsules/day × 10 days = 30 capsules. This is a standard calculation for determining total quantity to dispense based on sig codes and duration of therapy.", category: "Dosage Calculations", difficulty: 1 },
  ];

