  const bulkQuestions = [
    { stem: "Which type of drug recall is the MOST serious?", options: ["Class I", "Class II", "Class III", "Voluntary"], correctIndex: 0, rationale: "Class I recalls are the most serious, involving situations where there is a reasonable probability that the use of or exposure to the product will cause serious adverse health consequences or death.", category: "Inventory Management", difficulty: 1 },
    { stem: "What percentage of drugs does CYP3A4 metabolize approximately?", options: ["10%", "25%", "50%", "75%"], correctIndex: 2, rationale: "CYP3A4 metabolizes approximately 50% of all clinically used drugs, making it the most important cytochrome P450 enzyme. This is why CYP3A4 drug interactions are so clinically significant.", category: "Drug Interactions", difficulty: 2 },
    { stem: "What does PCN stand for in insurance billing?", options: ["Prescription Claim Number", "Processor Control Number", "Patient Coverage Network", "Pharmacy Certification Number"], correctIndex: 1, rationale: "PCN stands for Processor Control Number, which identifies the specific claims processor for the insurance plan. Along with BIN, Group Number, and Member ID, it's essential for processing pharmacy insurance claims.", category: "Prescription Processing", difficulty: 2 },
    { stem: "Which drug must be dispensed with a Medication Guide at every fill?", options: ["Amoxicillin", "Metformin", "Isotretinoin", "Levothyroxine"], correctIndex: 2, rationale: "Isotretinoin requires a Medication Guide at every dispensing through the iPLEDGE REMS program. It's a known teratogen requiring pregnancy prevention measures. Other drugs requiring Med Guides include certain opioids and antidepressants.", category: "Patient Safety", difficulty: 3 },
    { stem: "What is the maximum number of refills for a Schedule IV prescription?", options: ["0", "3", "5", "Unlimited"], correctIndex: 2, rationale: "Schedule IV prescriptions (like benzodiazepines) allow up to 5 refills within 6 months of the date written, the same as C-III and C-V. C-II drugs cannot be refilled at all.", category: "Regulations/Law", difficulty: 1 },
    { stem: "A 1:10,000 solution contains how many mg/mL?", options: ["0.01 mg/mL", "0.1 mg/mL", "1 mg/mL", "10 mg/mL"], correctIndex: 1, rationale: "1:10,000 = 1 g per 10,000 mL = 1000 mg per 10,000 mL = 0.1 mg/mL. Ratio strength is expressed as 1 gram in the given volume of solution.", category: "Dosage Calculations", difficulty: 3 },
    { stem: "Which law requires pharmacies to verify the drug supply chain?", options: ["HIPAA", "DSCSA", "CSA", "FDCA"], correctIndex: 1, rationale: "The Drug Supply Chain Security Act (DSCSA) requires an electronic, interoperable system to identify and trace prescription drugs as they are distributed. It helps prevent counterfeit drugs from entering the supply chain.", category: "Regulations/Law", difficulty: 3 },
    { stem: "What is the brand name for metoprolol succinate?", options: ["Lopressor", "Toprol-XL", "Coreg", "Tenormin"], correctIndex: 1, rationale: "Toprol-XL is the brand name for metoprolol succinate (extended-release, given once daily). Lopressor is metoprolol tartrate (immediate-release, given BID). Coreg = carvedilol. Tenormin = atenolol.", category: "Pharmacology", difficulty: 2 },
    { stem: "What is the purpose of the alligation method?", options: ["Calculating pediatric doses", "Mixing two concentrations to achieve a desired concentration", "Determining IV drip rates", "Converting between measurement systems"], correctIndex: 1, rationale: "Alligation is a mathematical method used to determine the proportions of two different concentrations needed to produce a desired final concentration. It's commonly used in compounding.", category: "Dosage Calculations", difficulty: 3 },
    { stem: "Which federal agency enforces controlled substance regulations?", options: ["FDA", "CDC", "DEA", "CMS"], correctIndex: 2, rationale: "The Drug Enforcement Administration (DEA) enforces the Controlled Substances Act and regulates controlled substance manufacturing, distribution, and dispensing. The FDA regulates drug safety and efficacy.", category: "Regulations/Law", difficulty: 1 },
    { stem: "ACE inhibitors are contraindicated in which patient population?", options: ["Diabetic patients", "Elderly patients", "Pregnant patients", "Pediatric patients"], correctIndex: 2, rationale: "ACE inhibitors (drugs ending in -pril) are absolutely contraindicated in pregnancy due to teratogenic effects including fetal renal damage, oligohydramnios, and skull defects. Pregnancy Category X.", category: "Pharmacology", difficulty: 2 },
    { stem: "What is the correct way to read a graduated cylinder?", options: ["At the top of the meniscus", "At the bottom of the meniscus", "At the center of the liquid column", "From any angle"], correctIndex: 1, rationale: "Always read a graduated cylinder at the bottom of the meniscus (the curved surface of the liquid) at eye level. Reading from above or below introduces parallax error, leading to inaccurate measurements.", category: "Compounding", difficulty: 1 },
    { stem: "Which vitamin supplement significantly interacts with warfarin?", options: ["Vitamin A", "Vitamin B12", "Vitamin C", "Vitamin K"], correctIndex: 3, rationale: "Vitamin K directly counteracts warfarin's mechanism. Warfarin inhibits vitamin K-dependent clotting factors (II, VII, IX, X). High vitamin K intake from supplements or green leafy vegetables reduces warfarin's anticoagulant effect.", category: "Drug Interactions", difficulty: 1 },
    { stem: "The buffer room in a sterile compounding facility is classified as:", options: ["ISO Class 5", "ISO Class 6", "ISO Class 7", "ISO Class 8"], correctIndex: 2, rationale: "The buffer room is classified as ISO Class 7 (Class 10,000). It houses the primary engineering control (LAFW/CAI) which provides ISO Class 5. The ante room is ISO Class 8.", category: "Sterile Products", difficulty: 2 },
    { stem: "What is the primary difference between metoprolol tartrate and metoprolol succinate?", options: ["Different drug class", "Different route of administration", "Different release formulation (IR vs ER)", "Different therapeutic indication"], correctIndex: 2, rationale: "Metoprolol tartrate (Lopressor) is immediate-release, given BID. Metoprolol succinate (Toprol-XL) is extended-release, given once daily. Both are the same drug with the same therapeutic class (beta-1 selective blocker).", category: "Pharmacology", difficulty: 2 },
    { stem: "Which organization publishes the 'Do Not Use' list of error-prone abbreviations?", options: ["FDA", "DEA", "ISMP", "The Joint Commission"], correctIndex: 3, rationale: "The Joint Commission publishes the official 'Do Not Use' list of dangerous abbreviations. ISMP publishes a more comprehensive error-prone abbreviations list. Both aim to prevent medication errors from misinterpreted abbreviations.", category: "Patient Safety", difficulty: 2 },
    { stem: "What is the generic name for Prilosec OTC?", options: ["Pantoprazole", "Omeprazole", "Esomeprazole", "Lansoprazole"], correctIndex: 1, rationale: "Omeprazole is the generic name for Prilosec/Prilosec OTC. Pantoprazole = Protonix, esomeprazole = Nexium, lansoprazole = Prevacid. All are PPIs but have different brand names.", category: "Pharmacology", difficulty: 1 },
    { stem: "How should a pharmacy technician handle a prescription with an unclear or illegible sig?", options: ["Guess the most likely interpretation", "Ask the patient what the doctor said", "Contact the prescriber for clarification", "Refuse to fill the prescription"], correctIndex: 2, rationale: "When a prescription contains unclear or illegible directions, the pharmacy technician should contact the prescriber's office for clarification. Never guess or interpret unclear prescriptions, as this could lead to medication errors.", category: "Patient Safety", difficulty: 1 },
    { stem: "What does 'PRN' mean on a prescription?", options: ["Before meals", "After meals", "As needed", "At bedtime"], correctIndex: 2, rationale: "PRN stands for 'pro re nata,' meaning 'as needed' or 'as the situation arises.' It indicates the patient should take the medication only when needed, not on a scheduled basis. AC = before meals, PC = after meals, QHS = at bedtime.", category: "Prescription Processing", difficulty: 1 },
    { stem: "What is the refrigerated storage temperature range for pharmaceuticals?", options: ["0-2°C (32-36°F)", "2-8°C (36-46°F)", "8-15°C (46-59°F)", "15-20°C (59-68°F)"], correctIndex: 1, rationale: "Refrigerated pharmaceutical storage is defined as 2-8°C (36-46°F). This is important for drugs like insulin (unopened), certain antibiotics after reconstitution, and many vaccines. Freezing (below 0°C) can damage many medications.", category: "Inventory Management", difficulty: 1 },
  ];

