  const finalQuestions = [
    { stem: "What is the mechanism of action of statins?", options: ["Block calcium channels", "Inhibit HMG-CoA reductase", "Block angiotensin receptors", "Inhibit proton pump"], correctIndex: 1, rationale: "Statins inhibit HMG-CoA reductase, the rate-limiting enzyme in cholesterol synthesis. This reduces hepatic cholesterol production and upregulates LDL receptors, lowering blood LDL cholesterol levels.", category: "Pharmacology", difficulty: 2 },
    { stem: "How many teaspoons equal one tablespoon?", options: ["2", "3", "4", "5"], correctIndex: 1, rationale: "1 tablespoon = 3 teaspoons = 15 mL. This is a fundamental household measurement conversion that pharmacy technicians must know for patient counseling and prescription calculations.", category: "Dosage Calculations", difficulty: 1 },
    { stem: "Which schedule of controlled substances requires DEA Form 222 for ordering?", options: ["Schedule I", "Schedule II", "Schedule III", "All schedules"], correctIndex: 1, rationale: "DEA Form 222 (or electronic CSOS ordering) is specifically required for ordering Schedule II controlled substances. C-III through C-V can be ordered with a regular purchase order. C-I drugs are not available for pharmacy dispensing.", category: "Regulations/Law", difficulty: 2 },
    { stem: "What is the correct order for cleaning a horizontal LAFW?", options: ["Front to back, bottom to top", "Back to front, top to bottom", "Side to side, then front", "Any direction is acceptable"], correctIndex: 1, rationale: "In a horizontal LAFW, clean from back to front (cleanest to dirtiest) and from top to bottom. This prevents contaminating already cleaned areas. The HEPA filter is at the back, providing the cleanest air.", category: "Sterile Products", difficulty: 2 },
    { stem: "Which electrolyte is considered high-alert when available in concentrated form?", options: ["Sodium chloride 0.9%", "Potassium chloride concentrate", "Calcium gluconate 10%", "Magnesium sulfate 50%"], correctIndex: 1, rationale: "Potassium chloride (KCl) concentrate is an ISMP high-alert medication. Undiluted KCl can cause fatal cardiac arrhythmias. It must always be diluted before IV administration and should not be stored on nursing units.", category: "Patient Safety", difficulty: 2 },
    { stem: "What is the purpose of an ointment slab in compounding?", options: ["Sterilizing preparations", "Mixing and levigating compounds", "Measuring liquid volumes", "Storing finished products"], correctIndex: 1, rationale: "An ointment slab (ground glass plate) provides a flat, non-porous surface for mixing creams, ointments, and pastes using spatulation and levigation techniques. It can also be used with parchment paper for easy cleanup.", category: "Compounding", difficulty: 1 },
    { stem: "What information is NOT included in an NDC number?", options: ["Manufacturer/labeler", "Drug expiration date", "Product strength/dosage form", "Package size"], correctIndex: 1, rationale: "NDC numbers identify the labeler/manufacturer, product/strength/dosage form, and package size. Expiration date is NOT part of the NDC number. NDC = National Drug Code (10 digits).", category: "Prescription Processing", difficulty: 2 },
    { stem: "Rifampin is the strongest inducer of which enzyme?", options: ["CYP1A2", "CYP2D6", "CYP2C9", "CYP3A4"], correctIndex: 3, rationale: "Rifampin is the strongest known inducer of CYP3A4. It dramatically increases the metabolism of many drugs, reducing their effectiveness. Patients starting rifampin often need dose adjustments for other medications.", category: "Drug Interactions", difficulty: 3 },
    { stem: "What does VAERS stand for?", options: ["Vaccine Adverse Event Reporting System", "Voluntary Adverse Effects Reporting Service", "Verified Adverse Event Registry System", "Vaccine Assessment and Evaluation Research System"], correctIndex: 0, rationale: "VAERS (Vaccine Adverse Event Reporting System) is the national system for reporting adverse events following vaccination. It is co-managed by the CDC and FDA. Healthcare providers are required to report certain events.", category: "Patient Safety", difficulty: 2 },
    { stem: "What type of insulin can be given intravenously?", options: ["NPH", "Glargine", "Regular", "Detemir"], correctIndex: 2, rationale: "Regular (short-acting) insulin is the only insulin type that can be administered intravenously. NPH, glargine, and detemir are formulated for subcutaneous injection only. IV regular insulin is used for DKA and hyperkalemia.", category: "Pharmacology", difficulty: 3 },
    { stem: "What is the default beyond-use date for non-sterile solid preparations without stability data?", options: ["14 days", "30 days", "90 days", "180 days"], correctIndex: 3, rationale: "Per USP <795>, non-sterile solid preparations (capsules, tablets, powders) without specific stability data should be assigned a BUD of 180 days or the earliest expiration date of any component, whichever is shorter.", category: "Compounding", difficulty: 2 },
    { stem: "Which law protects patient health information?", options: ["CSA", "HIPAA", "FDCA", "OBRA"], correctIndex: 1, rationale: "HIPAA (Health Insurance Portability and Accountability Act) of 1996 established national standards for protecting patients' Protected Health Information (PHI). It covers privacy, security, and breach notification.", category: "Regulations/Law", difficulty: 1 },
    { stem: "How should a pharmacy technician verify a DEA number for validity?", options: ["Call the DEA directly", "Check the prescriber's medical license", "Use the mathematical checksum formula", "Contact the state board of pharmacy"], correctIndex: 2, rationale: "The DEA number can be verified using the checksum formula: Sum positions 1,3,5 + (2 × sum of positions 2,4,6). The last digit of the result should equal the check digit (last digit of the DEA number).", category: "Regulations/Law", difficulty: 3 },
    { stem: "What is the purpose of a HEPA filter in sterile compounding?", options: ["Removes odors from the air", "Filters particles ≥0.3 μm with 99.97% efficiency", "Sterilizes all air passing through", "Controls humidity levels"], correctIndex: 1, rationale: "HEPA (High-Efficiency Particulate Air) filters remove at least 99.97% of airborne particles 0.3 μm or larger. They create the clean air environment in LAFWs and cleanrooms needed for sterile compounding.", category: "Sterile Products", difficulty: 2 },
    { stem: "Which medication should NOT be crushed?", options: ["Amoxicillin capsules", "Metoprolol succinate (Toprol-XL)", "Ibuprofen tablets", "Metformin immediate-release"], correctIndex: 1, rationale: "Metoprolol succinate (Toprol-XL) is an extended-release formulation that should never be crushed. Crushing would destroy the sustained-release mechanism, causing the entire dose to be released at once, potentially causing toxicity.", category: "Pharmacology", difficulty: 2 },
    { stem: "What is a formulary?", options: ["A list of expired medications", "An approved list of medications covered by an insurance plan or institution", "A database of drug interactions", "A register of controlled substances"], correctIndex: 1, rationale: "A formulary is a list of medications approved for use within a healthcare system or covered by an insurance plan. The Pharmacy and Therapeutics (P&T) committee manages the formulary in institutional settings.", category: "Inventory Management", difficulty: 1 },
    { stem: "Levothyroxine absorption is decreased by which of the following?", options: ["Vitamin B12", "Omega-3 fatty acids", "Calcium supplements", "Vitamin D"], correctIndex: 2, rationale: "Calcium supplements (and calcium-containing antacids, iron supplements) decrease levothyroxine absorption by forming insoluble complexes. Levothyroxine should be taken alone, 30-60 minutes before any food or other medications.", category: "Drug Interactions", difficulty: 2 },
    { stem: "What is the most common type of medication error?", options: ["Wrong patient", "Wrong route", "Wrong drug dispensed", "Wrong dose"], correctIndex: 2, rationale: "Dispensing the wrong drug is the most common type of medication error, often caused by look-alike/sound-alike drug names, similar packaging, or adjacent shelf placement. The three-point check helps prevent these errors.", category: "Patient Safety", difficulty: 1 },
    { stem: "What is the brand name for losartan?", options: ["Norvasc", "Cozaar", "Diovan", "Benicar"], correctIndex: 1, rationale: "Cozaar is the brand name for losartan, an angiotensin II receptor blocker (ARB). Norvasc = amlodipine (CCB), Diovan = valsartan (ARB), Benicar = olmesartan (ARB). Note: all ARBs end in -sartan.", category: "Pharmacology", difficulty: 1 },
    { stem: "Convert 98.6°F to Celsius:", options: ["35°C", "37°C", "39°C", "40°C"], correctIndex: 1, rationale: "°C = (°F - 32) × 5/9 = (98.6 - 32) × 5/9 = 66.6 × 5/9 = 37°C. Normal body temperature is 98.6°F = 37°C. This conversion is used in clinical and compounding settings.", category: "Dosage Calculations", difficulty: 2 },
    { stem: "What does 'UD' mean as a sig code?", options: ["Until discontinued", "As directed", "Undiluted", "Unit dose"], correctIndex: 1, rationale: "UD stands for 'ut dictum,' meaning 'as directed.' The prescriber expects the patient to know how to use the medication based on prior counseling. It's less specific than other sig codes.", category: "Prescription Processing", difficulty: 2 },
    { stem: "Which antibiotic class is associated with tendon damage in children?", options: ["Penicillins", "Cephalosporins", "Fluoroquinolones", "Macrolides"], correctIndex: 2, rationale: "Fluoroquinolones (ciprofloxacin, levofloxacin, moxifloxacin — suffix -floxacin) carry a boxed warning for tendinitis and tendon rupture. They are generally avoided in patients under 18 years old.", category: "Pharmacology", difficulty: 3 },
    { stem: "What is the par level in inventory management?", options: ["Maximum stock quantity", "Minimum stock quantity triggering reorder", "Average daily usage", "Safety stock amount"], correctIndex: 1, rationale: "Par level is the minimum quantity of a drug that must be maintained in inventory. When stock falls to the par level, a reorder is automatically triggered to prevent stockouts while avoiding excess inventory.", category: "Inventory Management", difficulty: 1 },
    { stem: "An IV set has a drop factor of 60 gtt/mL. This is called a:", options: ["Macrodrip set", "Microdrip set", "Standard drip set", "Minidrip set"], correctIndex: 1, rationale: "A 60 gtt/mL drop factor indicates a microdrip (also called minidrip) set. Macrodrip sets have drop factors of 10, 15, or 20 gtt/mL. Microdrip sets deliver smaller drops, useful for pediatric and precise infusions.", category: "Dosage Calculations", difficulty: 2 },
  ];

